import{_ as r,W as n,X as i,Y as a,Z as t,$ as l,a0 as e,C as h}from"./framework-174e6972.js";const s={},o=e('<h2 id="_1-java的特点" tabindex="-1"><a class="header-anchor" href="#_1-java的特点" aria-hidden="true">#</a> 1. Java的特点</h2><ul><li>Java是基于JVM虚拟机的跨平台语言，一次编写，到处运行；</li><li>Java程序易于编写，而且有内置垃圾收集，不必考虑内存管理；</li><li>Java虚拟机拥有工业级的稳定性和高度优化的性能，且经过了长时期的考验；</li><li>Java拥有最广泛的开源社区支持，各种高质量组件随时可用。</li></ul><h3 id="_1-1-java语言发展史-了解" tabindex="-1"><a class="header-anchor" href="#_1-1-java语言发展史-了解" aria-hidden="true">#</a> 1.1 Java语言发展史（了解）</h3><p>语言：人与人交流沟通的表达方式</p><p>计算机语言：人与计算机之间进行信息交流沟通的一种特殊语言</p><p>Java语言是美国Sun公司（Stanford University Network）在1995年推出的计算机语言</p><p>Java之父：詹姆斯·高斯林（James Gosling）</p>',7),J={href:"https://www.oracle.com/",target:"_blank",rel:"noopener noreferrer"},c=e('<p>当前，我们学习使用的JDK版本：11.0</p><h3 id="_1-2-java语言跨平台原理-理解" tabindex="-1"><a class="header-anchor" href="#_1-2-java语言跨平台原理-理解" aria-hidden="true">#</a> 1.2 Java语言跨平台原理（理解）</h3><p>Java程序并非是直接运行的，Java编译器将Java源程序编译成与平台无关的字节码文件(class文件)，然后由Java虚拟机（JVM）对字节码文件解释执行。所以在不同的操作系统下，只需安装不同的Java虚拟机即可实现java程序的跨平台。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaBase/1.JavaBase/202304191644203.png" alt="image-20210923091350952" loading="lazy"></p><h2 id="_2-java版本-se、ee、me" tabindex="-1"><a class="header-anchor" href="#_2-java版本-se、ee、me" aria-hidden="true">#</a> 2. Java版本（SE、EE、ME）</h2><p>Java分为三个版本，分别如下：</p><ul><li>Java SE：Standard Edition，标准版</li><li>Java EE：Enterprise Edition，企业版</li><li>Java ME：Micro Edition，瘦身版</li></ul><h3 id="_2-1-不同版本的区别" tabindex="-1"><a class="header-anchor" href="#_2-1-不同版本的区别" aria-hidden="true">#</a> 2.1. 不同版本的区别</h3><table><thead><tr><th style="text-align:left;">三个不同版本</th><th style="text-align:left;">解析</th></tr></thead><tbody><tr><td style="text-align:left;">Java SE</td><td style="text-align:left;">包含标准的JVM和标准库</td></tr><tr><td style="text-align:left;">Java EE</td><td style="text-align:left;">在Java SE的基础上加上了大量的API和库，以便方便开发Web应用、数据库、消息服务等，Java EE的应用使用的虚拟机和Java SE完全相同</td></tr><tr><td style="text-align:left;">Java ME</td><td style="text-align:left;">针对嵌入式设备的“瘦身版”，Java SE的标准库无法在Java ME上使用，Java ME的虚拟机也是“瘦身版”，不建议学习Java ME</td></tr></tbody></table><h2 id="_3-jdk和jre" tabindex="-1"><a class="header-anchor" href="#_3-jdk和jre" aria-hidden="true">#</a> 3. JDK和JRE</h2><table><thead><tr><th>名词</th><th>完整英文</th><th>解析</th></tr></thead><tbody><tr><td>JDK</td><td>Java Development Kit</td><td>Java源码，要编译成Java字节码，就需要JDK，因为JDK除了包含JRE，还提供了编译器、调试器等开发工具，JDK=JRE+开发工具</td></tr><tr><td>JRE</td><td>Java Runtime Environment</td><td>运行Java字节码的虚拟机，JRE=JVM+核心类库</td></tr></tbody></table><p>二者关系如下：</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaBase/1.JavaBase/202304041649172.png" alt="JDK和JRE的关系.png" loading="lazy"></p><div class="hint-container info"><p class="hint-container-title">总结</p><p>JDK开发Java程序，JRE运行Java程序</p><p>我们做java开发安装JDK即可，它包含了java的运行环境和虚拟机，如果是打包好的项目给客户运行，那么只用安装JRE即可。</p></div><h2 id="_4-安装jdk" tabindex="-1"><a class="header-anchor" href="#_4-安装jdk" aria-hidden="true">#</a> 4. 安装JDK</h2><p>按不同平台自行搜索安装步骤。</p><h3 id="_4-1-jdk的安装目录介绍" tabindex="-1"><a class="header-anchor" href="#_4-1-jdk的安装目录介绍" aria-hidden="true">#</a> 4.1 JDK的安装目录介绍</h3><table><thead><tr><th>目录名称</th><th>说明</th></tr></thead><tbody><tr><td>bin</td><td>该路径下存放了JDK的各种工具命令。javac和java就放在这个目录。</td></tr><tr><td>conf</td><td>该路径下存放了JDK的相关配置文件。</td></tr><tr><td>include</td><td>该路径下存放了一些平台特定的头文件。</td></tr><tr><td>jmods</td><td>该路径下存放了JDK的各种模块。</td></tr><tr><td>legal</td><td>该路径下存放了JDK各模块的授权文档。</td></tr><tr><td>lib</td><td>该路径下存放了JDK工具的一些补充JAR包。</td></tr></tbody></table>',18);function v(p,_){const d=h("ExternalLinkIcon");return n(),i("div",null,[o,a("p",null,[t("2009年，Sun公司被甲骨文公司收购，所以我们现在访问oracle官网即可："),a("a",J,[t("https://www.oracle.com"),l(d)])]),c])}const f=r(s,[["render",v],["__file","1.Java-base.html.vue"]]);export{f as default};
